    html += '</div>';

    grid.innerHTML = html;
}

function updateApplianceStatusList(devices) {
    const list = document.getElementById('applianceStatusList');
    if (!list) return;

    let html = '';
    devices.forEach(device => {
        const isActive = device.power_watts > 5;
        html += `
