    --bg-primary: #1a2332;
    --bg-secondary: #243447;
    --bg-card: #2a3f5f;
    --text-primary: #ffffff;
    --text-secondary: #b0c4de;
    --accent-teal: #4ecdc4;
    --accent-yellow: #ffd166;
    --accent-pink: #ff6b9d;
    --accent-purple: #c77dff;
    --accent-green: #06ffa5;
    --accent-red: #ff4757;
    --border-color: #3d5a80;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: var(--bg-primary);
    color: var(--text-primary);
    overflow-x: hidden;
    transition: background 0.5s ease, color 0.5s ease;
}

/* Theme Transition Animations */
.app-container,
.sidebar,
.main-content,
.card,
.nav-item,
.theme-section {
    transition: all 0.5s ease;
}

button,
.toggle-label,
.action-btn,
.theme-btn {
    transition: all 0.3s ease;
}

.chart-container canvas {
    transition: all 0.5s ease;
}

/* ==================== APP CONTAINER ==================== */

.app-container {
    display: flex;
    min-height: 100vh;
    position: relative;
    z-index: 1;
}

/* ==================== PARTICLE CANVAS ==================== */

#particle-canvas {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    z-index: 0;
    overflow: hidden;
}

/* ==================== SIDEBAR ==================== */

.sidebar {
    width: 250px;
    background: #1a1f3a;
    padding: 30px 20px;
    display: flex;
    flex-direction: column;
    position: fixed;
    height: 100vh;
    border-right: 1px solid var(--border-color);
}

.logo {
    margin-bottom: 50px;
}

.logo h1 {
    font-size: 1.5em;
    font-weight: 600;
    letter-spacing: 2px;
    color: var(--text-primary);
}

.beta-badge {
    display: inline-block;
    background: var(--accent-pink);
    color: white;
    font-size: 0.7em;
    padding: 3px 8px;
    border-radius: 4px;
    margin-left: 10px;
    font-weight: bold;
}

.nav-menu {
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.nav-item {
    display: flex;
    align-items: center;
