    font-weight: 600;
}

.appliance-card-status.active {
    background: rgba(6, 255, 165, 0.2);
    color: var(--accent-green);
}

.appliance-card-status.inactive {
    background: rgba(255, 255, 255, 0.1);
    color: var(--text-secondary);
}

.appliance-card-power {
    font-size: 1.8em;
    font-weight: bold;
    color: var(--text-primary);
    margin-bottom: 5px;
}

.appliance-card-mode {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.appliance-status-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.status-item {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 12px 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.status-indicator {
    width: 12px;
    height: 12px;
    border-radius: 50%;
}

.status-indicator.on {
    background: var(--accent-green);
    box-shadow: 0 0 10px var(--accent-green);
}

.status-indicator.off {
    background: var(--text-secondary);
}

.status-name {
    flex: 1;
    font-size: 0.95em;
    color: var(--text-primary);
}

.status-power {
    font-size: 0.9em;
    color: var(--text-secondary);
}

/* ==================== ROOMS TAB ==================== */

.rooms-summary {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 20px;
    margin-bottom: 30px;
}

.room-card {
    background: var(--bg-secondary);
    border-radius: 12px;
    padding: 25px 20px;
    text-align: center;
    transition: transform 0.3s ease;
}

.room-card:hover {
    transform: translateY(-5px);
}

.room-icon {
    font-size: 2.5em;
    margin-bottom: 15px;
}

.room-name {
    font-size: 1em;
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 10px;
}

.room-usage {
    font-size: 1.3em;
    font-weight: bold;
    color: var(--accent-teal);
}

.room-details-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.room-detail-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.room-detail-name {
    font-size: 0.95em;
    color: var(--text-primary);
}

.room-detail-usage {
    font-size: 1em;
    font-weight: bold;
    color: var(--accent-teal);
}

/* ==================== RESPONSIVE DESIGN ==================== */

@media (max-width: 1200px) {
    .dashboard-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 900px) {
    .sidebar {
        width: 70px;
        padding: 20px 10px;
    }

    .logo h1,
    .beta-badge,
    .nav-item span:not(.icon) {
        display: none;
    }

    .nav-item {
        justify-content: center;
        padding: 15px;
    }

    .main-content {
        margin-left: 70px;
    }
}

@media (max-width: 600px) {
    .header {
        flex-direction: column;
        gap: 15px;
        align-items: flex-start;
    }

    .cost-comparison {
        flex-direction: column;
        gap: 20px;
    }
}

/* ==================== DEVICES TAB ==================== */

.devices-header {
    margin-bottom: 20px;
}

.devices-stats {
    display: flex;
    gap: 30px;
    flex-wrap: wrap;
}

.device-stat {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 20px 30px;
    background: var(--bg-secondary);
    border-radius: 12px;
    min-width: 120px;
}

.stat-number {
    font-size: 2.5em;
    font-weight: bold;
    color: var(--accent-teal);
    margin-bottom: 5px;
}

.stat-label {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.devices-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 20px;
}

.devices-cards {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 20px;
}

.device-card {
    background: var(--bg-secondary);
    border-radius: 12px;
    padding: 20px;
    transition: all 0.3s ease;
    border: 2px solid transparent;
}

.device-card.active {
    border-color: var(--accent-green);
    background: rgba(6, 255, 165, 0.05);
}

.device-card.inactive {
    border-color: transparent;
    opacity: 0.7;
}

.device-card:hover {
    transform: translateY(-5px);
}

.device-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 15px;
}

.device-icon {
    font-size: 2em;
}

.device-toggle {
    position: relative;
}

.toggle-switch {
    display: none;
}

.toggle-label {
    display: block;
    width: 50px;
    height: 26px;
    background: var(--bg-primary);
    border-radius: 13px;
    position: relative;
    cursor: pointer;
    transition: all 0.3s ease;
}

.toggle-label::after {
    content: '';
    position: absolute;
    width: 20px;
    height: 20px;
    background: var(--text-secondary);
    border-radius: 50%;
    top: 3px;
    left: 3px;
    transition: all 0.3s ease;
}

.toggle-switch:checked + .toggle-label {
    background: var(--accent-green);
}

.toggle-switch:checked + .toggle-label::after {
    left: 27px;
    background: white;
}

.device-card-name {
    font-size: 1.1em;
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 5px;
}

.device-card-room {
    font-size: 0.85em;
    color: var(--text-secondary);
    margin-bottom: 15px;
}

.device-card-power {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.power-value {
    font-size: 1.2em;
    font-weight: bold;
    color: var(--text-primary);
}

.power-status {
    font-size: 0.8em;
    padding: 4px 10px;
    border-radius: 12px;
    font-weight: 600;
}

.power-status.on {
    background: rgba(6, 255, 165, 0.2);
    color: var(--accent-green);
}

.power-status.off {
    background: rgba(255, 255, 255, 0.1);
    color: var(--text-secondary);
}

.device-scheduled {
    display: inline-block;
    font-size: 0.75em;
    color: var(--accent-yellow);
    margin-top: 10px;
    padding: 4px 8px;
    background: rgba(255, 209, 102, 0.1);
    border-radius: 4px;
}

/* ==================== SCHEDULES LIST ==================== */

.schedules-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.schedule-item {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.schedule-info {
    flex: 1;
}

.schedule-device {
    font-size: 0.95em;
    font-weight: 600;
    color: var(--text-primary);
    display: block;
    margin-bottom: 3px;
}

.schedule-time {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.schedule-status {
    font-size: 0.8em;
    padding: 5px 12px;
    border-radius: 12px;
    font-weight: 600;
}

.schedule-status.enabled {
    background: rgba(6, 255, 165, 0.2);
    color: var(--accent-green);
}

.schedule-status.disabled {
    background: rgba(255, 255, 255, 0.1);
    color: var(--text-secondary);
}

.schedule-delete {
    background: none;
    border: none;
    color: var(--accent-red);
    font-size: 1.2em;
    cursor: pointer;
    padding: 5px;
    opacity: 0.7;
    transition: opacity 0.3s ease;
}

.schedule-delete:hover {
    opacity: 1;
}

.no-schedules {
    text-align: center;
    color: var(--text-secondary);
    font-size: 0.9em;
    padding: 30px;
}

/* ==================== QUICK ACTIONS ==================== */

.quick-actions {
    display: flex;
    flex-direction: column;
    gap: 15px;
}

.action-btn {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 15px 20px;
    background: var(--bg-secondary);
    border: none;
    border-radius: 10px;
    color: var(--text-primary);
    font-size: 0.95em;
    cursor: pointer;
    transition: all 0.3s ease;
}

.action-btn:hover {
    background: var(--bg-card);
    transform: translateX(5px);
}

.action-icon {
    font-size: 1.5em;
}

#turnAllOff:hover {
    background: rgba(255, 71, 87, 0.2);
    color: var(--accent-red);
}

#turnAllOn:hover {
    background: rgba(6, 255, 165, 0.2);
    color: var(--accent-green);
}

#ecoMode:hover {
    background: rgba(78, 205, 196, 0.2);
    color: var(--accent-teal);
}

/* ==================== CYBER THEME SPECIAL EFFECTS ================== */

