}

body[data-theme="germany"] {
    font-family: var(--font);
}

body[data-theme="scandinavia"] {
    font-family: var(--font);
}

body[data-theme="tropical"] {
    font-family: var(--font);
}

body[data-theme="nordic"] {
    font-family: var(--font);
}

/* ==================== FLOATING ANIMATIONS ==================== */

@keyframes float {
    0%, 100% {
        transform: translateY(0px);
    }
    50% {
        transform: translateY(-10px);
    }
}

@keyframes floatDelayed {
    0%, 100% {
        transform: translateY(0px);
    }
    50% {
        transform: translateY(-8px);
    }
}

@keyframes sway {
    0%, 100% {
        transform: rotate(-2deg);
    }
    50% {
        transform: rotate(2deg);
    }
}

@keyframes pulseSoft {
    0%, 100% {
        opacity: 1;
    }
    50% {
        opacity: 0.7;
    }
}

@keyframes shimmer {
    0% {
        background-position: -200% 0;
    }
    100% {
        background-position: 200% 0;
    }
}

/* Japan Theme Animations */
body[data-theme="japan"] .card {
    animation: floatDelayed 4s ease-in-out infinite;
}

body[data-theme="japan"] .card:nth-child(2n) {
    animation-delay: 1s;
}

body[data-theme="japan"] .card:nth-child(3n) {
    animation-delay: 2s;
}

body[data-theme="japan"] .logo {
    animation: sway 3s ease-in-out infinite;
}

/* Germany Theme Animations */
body[data-theme="germany"] .card:hover {
    transform: scale(1.02);
}

body[data-theme="germany"] .card {
    transition: all 0.3s ease;
}

body[data-theme="germany"] .nav-item {
    transition: all 0.3s ease;
}

/* Tropical Theme Animations */
body[data-theme="tropical"] .card {
    animation: float 3s ease-in-out infinite;
}

body[data-theme="tropical"] .card:nth-child(odd) {
    animation-direction: alternate-reverse;
}

body[data-theme="tropical"] .logo {
    animation: pulseSoft 2s ease-in-out infinite;
}

/* Nordic Theme Animations */
body[data-theme="nordic"] .card {
    animation: floatDelayed 5s ease-in-out infinite;
}

body[data-theme="nordic"] .card:hover {
    box-shadow: 0 12px 40px rgba(128, 222, 234, 0.25);
    transform: translateY(-5px);
}

body[data-theme="nordic"] .logo h1 {
    animation: nordicGlow 3s ease-in-out infinite, float 4s ease-in-out infinite;
}

@keyframes nordicGlow {
    0%, 100% {
        text-shadow: 0 0 20px rgba(128, 222, 234, 0.5);
    }
    50% {
        text-shadow: 0 0 40px rgba(128, 222, 234, 0.8), 0 0 60px rgba(128, 222, 234, 0.4);
    }
}

@keyframes float {
    0%, 100% {
        transform: translateY(0px);
    }
    50% {
        transform: translateY(-10px);
    }
}

@keyframes floatDelayed {
    0%, 100% {
        transform: translateY(0px);
    }
    50% {
        transform: translateY(-8px);
    }
}

/* Scandinavia Theme - Clean floating */
body[data-theme="scandinavia"] .card {
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

body[data-theme="scandinavia"] .card:hover {
    transform: translateY(-4px);
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.1);
}

/* Dark Theme - Subtle glow pulse */
body[data-theme="dark"] .card {
    transition: all 0.3s ease;
}

body[data-theme="dark"] .card:hover {
    box-shadow: 0 8px 30px rgba(78, 205, 196, 0.15);
}

body[data-theme="dark"] .nav-item.active {
    box-shadow: 0 0 15px rgba(78, 205, 196, 0.3);
}

/* Button hover effects */
.action-btn:hover {
    transform: translateX(5px) scale(1.02);
}

.device-card:hover {
    transform: translateY(-5px);
}

/* Smooth transitions for all interactive elements */
.card,
.nav-item,
.filter-btn,
.action-btn,
.device-card,
.theme-btn {
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Loading shimmer effect for cards */
.card::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(
        90deg,
        transparent,
        rgba(255, 255, 255, 0.05),
        transparent
    );
    animation: shimmer 3s infinite;
}

.card {
    position: relative;
    overflow: hidden;
}

/* Remove shimmer for tropical and nordic to preserve aesthetics */
body[data-theme="tropical"] .card::before,
body[data-theme="nordic"] .card::before,
body[data-theme="japan"] .card::before {
    display: none;
}

/* Chart container animations */
.chart-container {
    transition: all 0.5s ease;
}

.chart-container:hover {
    transform: scale(1.02);
}

/* Progress bar animations */
.green-progress {
    transition: width 1s ease-out;
}

/* Status indicator pulse */
.status-indicator.on {
    animation: pulseSoft 2s ease-in-out infinite;
}

/* Toggle switch animation enhancement */
.toggle-switch:checked + .toggle-label {
    transition: all 0.3s ease;
    box-shadow: 0 0 20px currentColor;
}

/* Schedule item hover */
.schedule-item:hover {
    background: rgba(255, 255, 255, 0.08);
    transform: translateX(5px);
}

/* Room card hover effect */
.room-card:hover {
    transform: translateY(-8px) scale(1.02);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
}

/* Cost card hover */
.cost-card:hover {
    transform: scale(1.05);
    background: var(--bg-card);
}

/* Stat number animation */
.stat-number {
    transition: all 0.3s ease;
}

.stat-number:hover {
    transform: scale(1.1);
    color: var(--accent-teal);
}

/* Logo animation on theme change */
.logo h1 {
    transition: all 0.5s ease;
}

/* Beta badge pulse */
.beta-badge {
    animation: pulseSoft 2s ease-in-out infinite;
}

/* Device card active state */
.device-card.active {
    animation: float 3s ease-in-out infinite;
}

/* Tab navigation active indicator */
.nav-item.active::after {
    content: '';
    position: absolute;
    right: 0;
    top: 50%;
    transform: translateY(-50%);
    width: 0;
    height: 0;
    border-top: 6px solid transparent;
    border-bottom: 6px solid transparent;
    border-right: 6px solid var(--accent-teal);
}

/* Remove tab indicator for themes with different styles */
body[data-theme="japan"] .nav-item.active::after,
body[data-theme="tropical"] .nav-item.active::after {
    display: none;
}

/* Quick action button ripple effect */
.action-btn::after {
    content: '';
    position: absolute;
    width: 100%;
    height: 100%;
    top: 0;
    left: 0;
    background: radial-gradient(circle, rgba(255,255,255,0.3) 0%, transparent 70%);
    opacity: 0;
    transition: opacity 0.3s ease;
    pointer-events: none;
}

.action-btn:hover::after {
    opacity: 1;
}

/* Theme button hover enhancement */
.theme-btn:hover {
    transform: scale(1.2) rotate(10deg);
}

.theme-btn.active {
    transform: scale(1.1);
}

/* Card title animation */
.card-title {
    transition: all 0.3s ease;
}

.card:hover .card-title {
    color: var(--accent-teal);
}

/* Savings amount animation */
.savings-amount,
.net-amount {
    transition: all 0.3s ease;
}

.savings-amount:hover,
.net-amount:hover {
    transform: scale(1.1);
    text-shadow: 0 0 20px currentColor;
}

/* Filter button active state */
.filter-btn.active {
    transform: scale(1.05);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.2);
}

/* All links and buttons cursor */
a, button {
    cursor: pointer;
}

/* Remove default button outlines */
button:focus,
a:focus {
    outline: none;
}

/* Smooth scroll behavior */
html {
    scroll-behavior: smooth;
}

/* Selection color */
::selection {
    background: var(--accent-teal);
    color: var(--bg-primary);
}
